proof:
-- Since $n \geq 1$, we have $n \leq 1$, which implies $n = 1$.
have hn : n ≤ 1 := by
  rcases n with ( _ | _ | n ) <;> simp_all +arith +decide;
  convert known_needs_n_min_one_calls [ ] _ using 1 ; simp_all +decide [ isExpert, allKnow ];
  exacts [ 1, 0, by simp +decide [ allKnow, after ] ];
grind

